import cadquery as cq

class BaseEdgeSelector(cq.Selector):
    def filter(self, objectList):
        res = []
        for o in objectList:
            if isinstance(o, cq.Edge) and o.geomType() in ("CIRCLE", "ELLIPSE"):
                try:
                    # Select the circular edges at the base of the pegs (Z = 2.5)
                    if abs(o.Center().z - 2.5) < 1e-3:
                        res.append(o)
                except:
                    pass
        return res

class TopInnerEdgeSelector(cq.Selector):
    def filter(self, objectList):
        res = []
        for o in objectList:
            if isinstance(o, cq.Edge) and o.geomType() in ("CIRCLE", "ELLIPSE"):
                try:
                    # Select the inner circular edges at the top of the pegs (Z = 17.5)
                    if abs(o.Center().z - 17.5) < 1e-3:
